mapper.select:
select 
    f.flow_id, f.ent_code, e.ent_name, f.flow_name, f.business_type, f.start_node_id, n.node_name as start_node_name, f.version,
    f.active, f.default_flow, f.description, f.create_time, f.update_time
from t_bas_approval_flow f
left join t_bas_enterprise e on e.ent_code = f.ent_code
left join t_bas_approval_node n on n.node_id = f.start_node_id



            and f.ent_code = #{entCode}



                and f.ent_code in

                    #{entCode}





        and f.flow_name like concat('%', #{flowName}, '%')


        and f.business_type = #{businessType}


        and f.version = #{version}


        and f.active = #{active}


        and f.default_flow = #{defaultFlow}


order by f.flow_id desc

select count(1)
from t_bas_approval_flow
where ent_code = #{entCode} and flow_name = #{flowName} and business_type = #{businessType} and version = #{version}

select count(1)
from t_bas_approval_flow t1
where
  exists ( select 1 from t_bas_approval_flow t2 where t2.flow_id = #{flowId} and t1.ent_code = t2.ent_code)
  and t1.flow_id != #{flowId} and t1.flow_name = #{flowName}
  and t1.business_type = #{businessType} and t1.version = #{version}

mapper.update:
update t_bas_approval_flow
flow_name = #{flowName}, business_type = #{businessType}, start_node_id = #{startNodeId}, version = #{version}, active = #{active}, default_flow = #{defaultFlow}, description = #{description},
where flow_id = #{flowId}

update t_bas_approval_flow set start_node_id = case flow_id
when #{flowId} then #{startNodeId}
end where flow_id in
#{flowId}
